import { Container, Row, Col, Card, Button, Badge, Pagination } from "react-bootstrap";
import { useState, useEffect, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { getAllEvents } from "../services/eventService";
import { getStoredUser } from "../services/authService";

function HomePage() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState("on_sale");
  const [currentPage, setCurrentPage] = useState(1);
  const navigate = useNavigate();

  const EVENTS_PER_PAGE = 6;
  const user = getStoredUser();
  const isAdmin = user?.role === "admin";

  const getBannerSrc = (bannerImage) => {
    if (!bannerImage) {
      return "/images/default-banner.jpg";  // Đảm bảo đường dẫn hình ảnh hợp lệ
    }

    if (
      bannerImage.startsWith("http://") ||
      bannerImage.startsWith("https://")
    ) {
      return bannerImage;
    }

    return `/images/${bannerImage}`;  // Lấy từ thư mục public/images
  };

  const getEventCategory = (event) => {
    const now = new Date();
    const eventDate = new Date(event.event_date);
    const status = event.status;

    if (status === "ended" || status === "cancelled" || eventDate < now) {
      return "ended";
    }

    if (status === "on_sale") {
      return "on_sale";
    }

    return "upcoming";
  };

  const getEventCategoryLabel = (category) => {
    switch (category) {
      case "on_sale":
        return "Đang được bán";
      case "upcoming":
        return "Sắp diễn ra";
      case "ended":
        return "Đã kết thúc";
      default:
        return "Không xác định";
    }
  };

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        setLoading(true);

        const response = await getAllEvents(isAdmin);

        const eventData = Array.isArray(response.data?.data)
          ? response.data.data
          : [];

        setEvents(eventData);
      } catch (error) {
        console.error("Lỗi khi tải sự kiện:", error);
        setEvents([]);
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, [isAdmin]);

  const counts = useMemo(() => {
    return {
      on_sale: events.filter((event) => getEventCategory(event) === "on_sale").length,
      upcoming: events.filter((event) => getEventCategory(event) === "upcoming").length,
      ended: events.filter((event) => getEventCategory(event) === "ended").length,
    };
  }, [events]);

  const filteredEvents = useMemo(() => {
    return events.filter((event) => getEventCategory(event) === activeFilter);
  }, [events, activeFilter]);

  const totalPages = Math.ceil(filteredEvents.length / EVENTS_PER_PAGE);

  const paginatedEvents = useMemo(() => {
    const start = (currentPage - 1) * EVENTS_PER_PAGE;
    return filteredEvents.slice(start, start + EVENTS_PER_PAGE);
  }, [filteredEvents, currentPage]);

  useEffect(() => {
    setCurrentPage(1);
  }, [activeFilter]);

  const renderPagination = () => {
    if (totalPages <= 1) return null;

    const items = [];

    items.push(
      <Pagination.Prev
        key="prev"
        disabled={currentPage === 1}
        onClick={() => setCurrentPage((prev) => prev - 1)}
      />
    );

    for (let page = 1; page <= totalPages; page++) {
      items.push(
        <Pagination.Item
          key={page}
          active={page === currentPage}
          onClick={() => setCurrentPage(page)}
        >
          {page}
        </Pagination.Item>
      );
    }

    items.push(
      <Pagination.Next
        key="next"
        disabled={currentPage === totalPages}
        onClick={() => setCurrentPage((prev) => prev + 1)}
      />
    );

    return (
      <div className="tb-pagination-wrap">
        <Pagination className="tb-pagination">{items}</Pagination>
      </div>
    );
  };

  return (
    <div className="tb-home-page">
      <Container fluid="xl" className="tb-home-container">
        <div className="tb-hero-wrap">
          <Row className="g-3">
            <Col lg={7}>
              <div className="tb-hero-card tb-hero-green">
                <div className="tb-hero-content">
                  <div className="tb-hero-tag">Concert Ticket</div>
                  <h2 className="tb-hero-title">
                    Khám phá sự kiện & trải nghiệm giải trí mới
                  </h2>
                  <p className="tb-hero-text">
                    Nền tảng vé concert dành cho người yêu âm nhạc, sự kiện và NFT ticket minh bạch.
                  </p>
                  <Button className="tb-white-btn" onClick={() => navigate("/home")}>
                    Xem chi tiết
                  </Button>
                </div>
              </div>
            </Col>

            <Col lg={5}>
              <div className="tb-hero-card tb-hero-dark">
                <div className="tb-hero-content">
                  <div className="tb-hero-tag">Concert nổi bật</div>
                  <h2 className="tb-hero-title small">
                    {events[0]?.title || "Sự kiện đặc biệt đang mở bán"}
                  </h2>
                  <p className="tb-hero-text">
                    {events[0]?.location || "TP.HCM - Hà Nội - Việt Nam"}
                  </p>
                  <Button
                    className="tb-white-btn"
                    onClick={() =>
                      navigate(events[0] ? `/event/${events[0].id}` : "/home")
                    }
                  >
                    Xem chi tiết
                  </Button>
                </div>
              </div>
            </Col>
          </Row>
        </div>

        <div className="tb-section-block">
          <div className="tb-section-title">Sự kiện đặc biệt</div>

          <div className="tb-filter-bar">
            <button
              className={`tb-filter-chip ${activeFilter === "on_sale" ? "active" : ""}`}
              onClick={() => setActiveFilter("on_sale")}
            >
              Đang được bán ({counts.on_sale})
            </button>

            <button
              className={`tb-filter-chip ${activeFilter === "upcoming" ? "active" : ""}`}
              onClick={() => setActiveFilter("upcoming")}
            >
              Sắp diễn ra ({counts.upcoming})
            </button>

            <button
              className={`tb-filter-chip ${activeFilter === "ended" ? "active" : ""}`}
              onClick={() => setActiveFilter("ended")}
            >
              Đã kết thúc ({counts.ended})
            </button>
          </div>

          {loading ? (
            <div className="text-center p-5 text-white">Đang tải danh sách sự kiện...</div>
          ) : (
            <>
              <Row className="g-4">
                {paginatedEvents.length > 0 ? (
                  paginatedEvents.map((event) => {
                    const category = getEventCategory(event);

                    return (
                      <Col md={6} xl={4} key={event.id}>
                        <Card className="tb-event-card h-100">
                          <div className="tb-event-image-wrap">
                          <Card.Img
  variant="top"
  src={event.banner_image ? `/images/${event.banner_image}` : "/images/default-banner.jpg"}
  alt={event.title}
  className="tb-event-image"
/>
                          </div>

                          <Card.Body className="tb-event-body">
                            <div className="d-flex justify-content-between align-items-start mb-2">
                              <Badge bg="light" text="dark" className="tb-light-badge">
                                Music
                              </Badge>
                              <small className="tb-date-text">
                                {new Date(event.event_date).toLocaleDateString("vi-VN")}
                              </small>
                            </div>

                            <div className={`tb-status-pill ${category}`} >
                              {getEventCategoryLabel(category)}
                            </div>

                            <Card.Title className="tb-event-title">
                              {event.title}
                            </Card.Title>

                            <Card.Text className="tb-event-location">
                              {event.location}
                            </Card.Text>

                            <Button
                              className="tb-outline-btn mt-auto"
                              onClick={() => navigate(`/event/${event.id}`)}
                            >
                              Xem chi tiết
                            </Button>
                          </Card.Body>
                        </Card>
                      </Col>
                    );
                  })
                ) : (
                  <Col md={12}>
                    <div className="tb-empty-box">
                      Không có sự kiện nào trong mục này.
                    </div>
                  </Col>
                )}
              </Row>

              {renderPagination()}
            </>
          )}
        </div>
      </Container>
    </div>
  );
}

export default HomePage;
